logger = logging.get_logger(__name__)

def _load_state_dict(model_id_or_path, device="cpu"):
    # --- 1. Single-file safetensors -------------------------------------------
    safe_path = cached_file(model_id_or_path, SAFE_WEIGHTS_NAME,
                            _raise_exceptions_for_missing_entries=False)
    if safe_path:
        return safe_load_file(safe_path, device=device)

    # --- 2. Sharded safetensors ----------------------------------------------
    index_path = cached_file(model_id_or_path, SAFE_WEIGHTS_INDEX_NAME,
                             _raise_exceptions_for_missing_entries=False)
    if index_path:
        shard_files, _ = get_checkpoint_shard_files(
            model_id_or_path, index_path, cache_dir=None, local_files_only=False
        )
        state = {}
        for shard in shard_files:
            state.update(safe_load_file(shard, device=device))
        return state

    # --- 3. Legacy .bin -------------------------------------------------------
    bin_path = cached_file(model_id_or_path, WEIGHTS_NAME,
                           _raise_exceptions_for_missing_entries=False)
    if bin_path:
        return torch.load(bin_path, map_location=device, weights_only=True)

    raise FileNotFoundError(
        f"No compatible weight files found under {model_id_or_path}"
    )

