# =========================
# Custom cache for GDN + QwenAttention (matches modeling_norm.py style)
# =========================
# =====================================================================================
# NEW CACHE CLASS
# =====================================================================================

class CustomCache(Cache):
    """
    A cache used for storing hidden states produced by flash linear attention models.
    Stores states per layer with support for recurrent_state, attn_state, conv_state, and ffn_state.
    """

    is_compileable = True

    def __init__(self, seen_tokens: int = 0) -> None:
        super().__init__()
        self.states: List[Dict[str, Any]] = []
        self._seen_tokens = seen_tokens

    def __getitem__(self, layer_idx: int) -> Dict[str, Any]:
        if layer_idx < len(self):
            return self.states[layer_idx]
        else:
            raise KeyError(f"Cache only has {len(self)} layers, attempted to access layer with index {layer_idx}")

    def __iter__(self):
        for state in self.states:
            yield state

    def __len__(self):
        return len(self.states)

    def update(
            self,
            recurrent_state: torch.Tensor = None,
            attn_state: Tuple[torch.Tensor, torch.Tensor] = None,
            conv_state: Tuple[torch.Tensor] = None,
            ffn_state: torch.Tensor = None,
            layer_idx: int = 0,
            offset: Optional[int] = 1,
            cache_kwargs: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        """
        Updates the cache with new states for the specified layer.
        """
        if layer_idx == 0:
            self._seen_tokens += offset

        if cache_kwargs is None:
            cache_kwargs = {}

        if attn_state is not None:
            input_size = attn_state[0].shape[-2]
            window_size = cache_kwargs.get('window_size', None)
            if not isinstance(attn_state, Tuple) or len(attn_state) != 2:
                raise ValueError("`attn_state` must be a tuple of two tensors for key/value states")

        if len(self.states) <= layer_idx:
            if attn_state is not None:
                window_size = cache_kwargs.get('window_size', None)
                if window_size is not None and input_size > window_size:
                    attn_state = (attn_state[0][..., -window_size:, :].contiguous(),
                                  attn_state[1][..., -window_size:, :].contiguous())
            state = dict(
                recurrent_state=recurrent_state,
                attn_state=attn_state,
                conv_state=conv_state,
                ffn_state=ffn_state
            )
            self.states.append(state)
        else:
            state = self.states[layer_idx]
            if attn_state is not None:
                if state['attn_state'] is None:
                    state['attn_state'] = attn_state
                else:
                    key_state, value_state = state['attn_state']
                    window_size = cache_kwargs.get('window_size', None)
                    if window_size is not None and key_state.shape[-2] == window_size:
                        key_state = key_state.roll(-input_size, 2)
                        value_state = value_state.roll(-input_size, 2)
                        key_state[..., -input_size:, :] = attn_state[0]
                        value_state[..., -input_size:, :] = attn_state[1]
                        attn_state = (key_state, value_state)
                    else:
                        attn_state = (torch.cat([key_state, attn_state[0]], 2),
                                      torch.cat([value_state, attn_state[1]], 2))
                    state['attn_state'] = attn_state
            if recurrent_state is not None:
                state['recurrent_state'] = recurrent_state
            if conv_state is not None:
                state['conv_state'] = conv_state
            if ffn_state is not None:
                state['ffn_state'] = ffn_state

        return state

    @property
    def seen_tokens(self):
        return self._seen_tokens

    @seen_tokens.setter
    def seen_tokens(self, value):
        self._seen_tokens = value

    def get_cache_length(self, layer_idx: Optional[int] = 0) -> int:
        """Returns the sequence length of the cached states."""
        if len(self.states) <= layer_idx:
            return 0
        elif self.states[layer_idx]['attn_state'] is None:
            return 0
        return self.states[layer_idx]['attn_state'][0].size(2)

    def get_seq_length(self, layer_idx: Optional[int] = 0) -> int:
        """Returns the sequence length of the cached states."""
        if len(self.states) <= layer_idx:
            return 0
        return self._seen_tokens

    def get_max_length(self) -> Optional[int]:
        """Returns the maximum sequence length. Cache does not have a maximum length."""
        return None

    def to_legacy_cache(self) -> Tuple:
        return tuple(self.states)

    @classmethod
    @torch.compiler.disable
    def from_legacy_cache(
            cls,
            past_key_values: Optional[Tuple] = None,
            seen_tokens: int = 0
    ):
        """Converts a cache in the legacy cache format into an equivalent Cache."""
        cache = cls(seen_tokens)
        if isinstance(past_key_values, list):
            for layer_idx in range(len(past_key_values)):
                cache.states.append(past_key_values[layer_idx])
        return cache

    def batch_select_indices(self, indices: torch.Tensor):
        """Select specific batch indices for beam search."""
        for layer_idx in range(len(self)):
            state = self.states[layer_idx]
            if state['attn_state'] is not None:
                state['attn_state'] = tuple(s[indices, ...] for s in state['attn_state'])
            if state['recurrent_state'] is not None:
                state['recurrent_state'] = state['recurrent_state'][indices, ...]
            if state['conv_state'] is not None:
                state['conv_state'] = tuple(s[indices, ...] if s is not None else None
                                            for s in state['conv_state'])
            if state['ffn_state'] is not None:
                state['ffn_state'] = state['ffn_state'][indices, ...]

    def batch_repeat_interleave(self, repeats: int):
        """Repeat batch indices for beam search."""
        for layer_idx in range(len(self)):
            state = self.states[layer_idx]
            if state['attn_state'] is not None:
                state['attn_state'] = tuple(s.repeat_interleave(repeats, dim=0) for s in state['attn_state'])
            if state['recurrent_state'] is not None:
                state['recurrent_state'] = state['recurrent_state'].repeat_interleave(repeats, dim=0)
            if state['conv_state'] is not None:
                state['conv_state'] = tuple(s.repeat_interleave(repeats, dim=0) if s is not None else None
                                            for s in state['conv_state'])
            if state['ffn_state'] is not None:
                state['ffn_state'] = state['ffn_state'].repeat_interleave(repeats, dim=0)



